tool_calls.cmd:
cd $WORKSPACE_DIR && echo "=== Final output directory ===" && ls -la output/ && echo "" && echo "=== Final validation ===" && python skills/docx/scripts/validate.py output/development-agreement-draft.docx 2>&1 && echo "EXIT: $?" && echo "" && echo "=== File size & word count ===" && du -h output/development-agreement-draft.docx && python3 -c "
from docx import Document
d=Document('output/development-agreement-draft.docx')
words=sum(len(p.text.split()) for p in d.paragraphs)
for t in d.tables:
    for r in t.rows:
        for c in r.cells: words+=len(c.text.split())
print('Approx word count:', words)
print('Paragraphs:', len(d.paragraphs), '| Tables:', len(d.tables))
"
